import{_ as e,c as t,o,a4 as r}from"./chunks/framework.OpyvxaCo.js";const g=JSON.parse('{"title":"Quick Start","description":"","frontmatter":{"sidebar_position":1},"headers":[],"relativePath":"joinus/index.md","filePath":"joinus/index.md","lastUpdated":1711637073000}'),a={name:"joinus/index.md"},s=r('<h1 id="quick-start" tabindex="-1">Quick Start <a class="header-anchor" href="#quick-start" aria-label="Permalink to &quot;Quick Start&quot;">​</a></h1><p>If you&#39;ve found a bug or have a suggestion for improving RSSHub, we&#39;d love to hear from you! You can submit your changes by creating a pull request. Don&#39;t worry if you&#39;re new to pull requests - we welcome contributions from developers of all experience levels. Don&#39;t know how to code? You can also help by <a href="https://github.com/DIYgod/RSSHub/issues" target="_blank" rel="noreferrer">reporting bugs</a>.</p><h2 id="join-the-discussion" tabindex="-1">Join the discussion <a class="header-anchor" href="#join-the-discussion" aria-label="Permalink to &quot;Join the discussion&quot;">​</a></h2><p><a href="https://t.me/rsshub" target="_blank" rel="noreferrer"><img src="https://img.shields.io/badge/chat-telegram-brightgreen.svg?logo=telegram&amp;style=for-the-badge" alt="Telegram Group"></a> <a href="https://github.com/DIYgod/RSSHub/issues" target="_blank" rel="noreferrer"><img src="https://img.shields.io/github/issues/DIYgod/RSSHub?color=bright-green&amp;logo=github&amp;style=for-the-badge" alt="GitHub issues"></a></p><h2 id="before-you-begin" tabindex="-1">Before you begin <a class="header-anchor" href="#before-you-begin" aria-label="Permalink to &quot;Before you begin&quot;">​</a></h2><p>To create an RSS feed, you&#39;ll need to use a combination of Git, HTML, JavaScript, jQuery, and Node.js.</p><p>If you don&#39;t know much about them but would like to learn them, here are some good resources:</p><ul><li><a href="https://developer.mozilla.org/en-US/docs/Web/JavaScript#tutorials" target="_blank" rel="noreferrer">JavaScript Tutorials on MDN Web Docs</a></li><li><a href="https://www.w3schools.com/" target="_blank" rel="noreferrer">W3Schools</a></li><li><a href="https://www.codecademy.com/learn/learn-git" target="_blank" rel="noreferrer">Git course on Codecademy</a></li></ul><p>If you&#39;d like to see examples of how other developers use these technologies to create RSS feeds, you can take a look at some of the code in <a href="https://github.com/DIYgod/RSSHub/tree/master/lib/routes" target="_blank" rel="noreferrer">our repository</a>.</p><h2 id="submit-new-rsshub-rules" tabindex="-1">Submit new RSSHub rules <a class="header-anchor" href="#submit-new-rsshub-rules" aria-label="Permalink to &quot;Submit new RSSHub rules&quot;">​</a></h2><p>If you&#39;ve found a website that doesn&#39;t offer an RSS feed, you can create an RSS rule for it using RSSHub. An RSS rule is a short Node.js program code (hereafter referred to as &quot;route&quot;) that tells RSSHub how to extract content from a website and generate an RSS feed. By creating a new RSS route, you can help make content from your favourite websites more accessible and easier to follow.</p><p>Before you start writing an RSS route, please make sure that the source site does not provide RSS. Some web pages will include a link element with type <code>application/atom+xml</code> or <code>application/rss+xml</code> in the HTML header to indicate the RSS link.</p><p>Here&#39;s an example of what an RSS link might look like in the HTML header: <code>&lt;link rel=&quot;alternate&quot; type=&quot;application/rss+xml&quot; href=&quot;http://example.com/rss.xml&quot; /&gt;</code>. If you see a link like this, it means that the website already has an RSS feed and you don&#39;t need to create a new RSS route for it.</p><h3 id="getting-started" tabindex="-1">Getting started <a class="header-anchor" href="#getting-started" aria-label="Permalink to &quot;Getting started&quot;">​</a></h3><p>In this guide, you&#39;ll learn how to create a new RSS route from scratch. We&#39;ll cover everything from setting up your development environment to submitting your code to the RSSHub repository. By the end of this guide, you&#39;ll be able to create your own RSS feeds for websites that don&#39;t offer them.</p><p><a href="/joinus/new-rss/prerequisites">Ready to get started? Click here to dive into the guide!</a></p><h2 id="submit-new-rsshub-radar-rules" tabindex="-1">Submit new RSSHub Radar rules <a class="header-anchor" href="#submit-new-rsshub-radar-rules" aria-label="Permalink to &quot;Submit new RSSHub Radar rules&quot;">​</a></h2><h3 id="before-you-start" tabindex="-1">Before you start <a class="header-anchor" href="#before-you-start" aria-label="Permalink to &quot;Before you start&quot;">​</a></h3><p>It&#39;s recommended that you download and install RSSHub Radar in your browser before you start.</p><p>Once you have installed RSSHub Radar, open the settings and switch to the &quot;List of rules&quot; tab. Then scroll down to the bottom of the page and you will see a text field. Here, you can replace the old rules with your new rules for debugging.</p><p><a href="/joinus/new-radar">Let&#39;s start!</a></p><p><a href="https://chrome.google.com/webstore/detail/rsshub-radar/kefjpfngnndepjbopdmoebkipbgkggaa" target="_blank" rel="noopener noreferrer"><img src="https://storage.googleapis.com/web-dev-uploads/image/WlD8wC6g8khYWPJUsQceQkhXSlv1/UV4C4ybeBTsZt43U4xis.png" alt="Get RSSHub Radar for Chromium" style="height:58px;"></a><a href="https://addons.mozilla.org/firefox/addon/rsshub-radar/" target="_blank" rel="noopener noreferrer"><img src="https://blog.mozilla.org/addons/files/2020/04/get-the-addon-fx-apr-2020.svg" alt="Get Get RSSHub Radar for Firefox" style="height:58px;"></a><a href="https://microsoftedge.microsoft.com/addons/detail/rsshub-radar/gangkeiaobmjcjokiofpkfpcobpbmnln" target="_blank" rel="noopener noreferrer"><img src="https://wsrv.nl/?url=https://upload.wikimedia.org/wikipedia/commons/f/f7/Get_it_from_Microsoft_Badge.svg" alt="Get RSSHub Radar for Edge" style="height:58px;"></a><a href="https://apps.apple.com/us/app/rsshub-radar/id1610744717" target="_blank" rel="noopener noreferrer"><img src="https://developer.apple.com/news/images/download-on-the-app-store-badge.png" alt="Get RSSHub Radar for Safari" style="height:58px;"></a></p>',22),i=[s];function n(l,u,d,h,p,c){return o(),t("div",null,i)}const f=e(a,[["render",n]]);export{g as __pageData,f as default};
